import{_ as p,o as e,c as a,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const C=JSON.parse('{"title":"水遁","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/能量类/忍术/五行遁术/水遁.md","filePath":"4.资源分区/6.技艺及称号/能量类/忍术/五行遁术/水遁.md"}'),s={name:"4.资源分区/6.技艺及称号/能量类/忍术/五行遁术/水遁.md"};function o(d,b,l,i,_,c){return e(),a("div",null,[...b[0]||(b[0]=[r("h1",{id:"水遁",tabindex:"-1"},[t("水遁 "),r("a",{class:"header-anchor",href:"#水遁","aria-label":'Permalink to "水遁"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘")])])],-1),n('<h1 id="水遁-1" tabindex="-1">水遁 <a class="header-anchor" href="#水遁-1" aria-label="Permalink to &quot;水遁&quot;">​</a></h1><p>水遁</p><p>【水铁炮之术】<br> D+500<br> 消耗能量：2点<br> 使用动作：标准<br> 遁术性质：水<br> 持续时间：立即<br> 目标：单体<br> 忍术成分：姿势、语言、忍印（可选）<br> 距离：操控*2米<br> 描述：将手作手枪状，从食指尖射出有如子弹的液体贯穿敌人。破坏力较强，可轻易破坏任何东西。是一种无需结印即可发动的强力高效水遁秘术。</p><p>效果：进行一次忍术攻击检定，对目标造成冻寒属性能量伤害，这次攻击具有破甲10与【连射】。</p><p>【水遁·水上切】<br> D+500<br> 消耗能量：2点<br> 使用动作：迅捷<br> 遁术性质：水<br> 持续时间：一场景<br> 目标：自身<br> 忍术成分：姿势、语言、忍印<br> 距离：无<br> 描述：这是一种将水流集中在脚部进行快速滑行的水遁忍术，即使是在土地上，也可以做到快速滑行的效果。还可以从脚部踢出刀刃状的水流攻击敌人。</p><p>效果：移动速度增加10米，从腿部施加的肉搏攻击触及范围提升2米，天生武器伤害提升至5L。</p><p>【雾隐之术】<br> C+1000<br> 消耗能量：6点<br> 使用动作：标准<br> 遁术性质：水<br> 持续时间：一场景<br> 目标：自身当前位置的地点<br> 忍术成分：姿势、语言、忍印<br> 距离：操控*6米<br> 描述：雾隐忍者常用的一种水遁忍术，此术有两种发动方式。一种是从口中吐出浓雾遮挡对手的视线。另一种是结印凝聚空气中的浓雾遮挡对手的视线。</p><p>效果：以使用者所处之地为圆心、操控*6米范围内的区域会逐渐升腾起雾气，雾气会在一轮内逐渐变得浓郁。一轮以后，雾气包裹的区域将变为浓雾天气，这是一个C级环境来源的效果。<br> 这一区域会满足使用C级及以下的、处于雾环境才能施展的能力限制。<br> 这一区域只会同时存在一个，你使用另一次本忍术后，原先区域会消失。</p><p>【水遁·水鲛弹之术】<br> C+1000<br> 消耗能量：6点<br> 使用动作：标准/整轮<br> 遁术性质：水<br> 持续时间：立即<br> 目标：单体<br> 忍术成分：姿势、语言、忍印<br> 距离：操控*3米/触及<br> 描述：凝聚查克拉形成鲨鱼状的水弹攻击敌人。用鲨鱼型水弹包裹住自己，还可以在半空中滑翔。</p><p>效果：进行一次忍术攻击检定，对目标造成冻寒能量伤害，此次伤害附带水属性能量6DP，附带基于水属性能量的1点附加成功，【10高速】。<br> 或者你额外花费一个移动动作使用本忍术，若如此做，你可以先进行一次机动性为普通的飞行移动，距离为移动速度的二倍。再对触及范围内的一个目标进行一次近战攻击，此次攻击视作一次冲锋攻击，具有C级措手不及与5点威猛。</p><p>差价升级至B+2000【水遁·大鲛弹之术】</p><p>【水遁·大鲛弹之术】<br> B+2000<br> 消耗能量：10点<br> 使用动作：标准<br> 遁术性质：水<br> 持续时间：立即<br> 目标：敌方单体<br> 忍术成分：姿势、语言、忍印<br> 距离：操控*5米<br> 描述：水遁·水鲛弹之术的升级版，破坏力更大，用查克拉瞬间制造一只超大的鲨鱼型水弹攻击敌人，如果水弹受到忍术攻击，则会瞬间吸光对方攻击中的查克拉，变得更加巨大。</p><p>效果：进行一次忍术攻击检定，此次攻击附带等同于操控属性点冻寒能量加值，附带基于水属性能量的1点附加成功。接着你会召唤出一头巨大的由查克拉凝聚的鲨鱼，鲨鱼会在一轮后扑向目标，对方需要以反射豁免，失败则受到差额的冻寒能量伤害。<br> 鲨鱼可以被带有能量的攻击方式选择为攻击目标，只要对方的攻击检定成功数大于你施展时的攻击检定成功数，鲨鱼会被摧毁化为漫天飞雨。<br> 但如果鲨鱼被攻击且没有被摧毁，则鲨鱼会吞噬对方的能量变得更加巨大，扑向目标后，目标周围的操控*3米内的所有敌方单位都需要进行反射豁免，并承受差额的冻寒能量伤害，目标针对这次反射豁免需要承受失败攻击中附加的能量点环境减值。</p><p>【水遁·爆水冲波】<br> C+1000<br> 消耗能量：6点<br> 使用动作：标准<br> 遁术性质：水<br> 持续时间：立即<br> 目标：扇形群体<br> 忍术成分：姿势、语言、忍印<br> 距离：操控*3米<br> 描述：使用此术可将查克拉聚集在喉咙后，朝地面喷吐足以形成湖泊的水冲击敌人</p><p>效果：进行一次忍术攻击检定，对扇形区域内的所有敌方目标造成冻寒能量伤害，此次攻击附带冻寒能量加值5DP，对方需要以反射豁免伤害。如果对方受到伤害，将被击退差值+15米。</p><p>差价升级至B+2000【水遁·大爆水冲波】</p><p>【水遁·大爆水冲波】<br> B+2000<br> 消耗能量：10点<br> 使用动作：标准<br> 遁术性质：水<br> 持续时间：一场景<br> 目标：自身所在的固定地点<br> 忍术成分：姿势、语言、忍印<br> 距离：操控*8米<br> 描述：此术属于水遁系防御型忍术。从口中猛烈喷出海浪的水瞬间形成巨大的椭球型水牢囚禁住敌人。施术者可以在水中自由翱翔。</p><p>效果：自身所处位置为圆心、高度为操控*2米、半径为操控*8米的圆形范围内的区域在一轮内会快速充满水，在一轮后，这一区域会成为B级环境来源的水中环境。这一水中环境中，想通过游泳以避免困难地形的DC提高至18点。<br> 你可于这一区域正常呼吸，在水下移动。<br> 此范围内施展的水属性忍术获得冻寒能量加值8DP与基于冻寒属性能量的一点附加成功。<br> 这一区域只会同时存在一个，你使用另一次本忍术后，原先区域会消失。</p><p>【水遁·水流鞭】<br> C+1000<br> 消耗能量：6点<br> 使用动作：标准<br> 遁术性质：水<br> 持续时间：立即<br> 目标：单体<br> 忍术成分：姿势、语言、忍印<br> 距离：操控*3米<br> 描述：以水形成鞭子捆绑住敌人使其不能动弹.</p><p>效果：进行一次忍术攻击检定，此次伤害附带冻寒能量加值4DP，基于冻寒属性能量的附加成功2点，【高速10】，造成的伤害转换为纠缠点数，正常豁免。</p><p>【水牢术】<br> C+1000<br> 消耗能量：6点<br> 使用动作：整轮<br> 维持动作：见下<br> 遁术性质：水<br> 持续时间：特殊<br> 目标：触及范围内单体目标<br> 描述：利用水流形成球形的牢笼包住敌人，施术者只要单手插在水牢里，就能把敌人困住</p><p>效果：以忍术攻击检定进行一次擒抱命中检定，正常对抗。你在这次命中检定与后续擒抱对抗、压制行为中具有等于使用者敏捷属性点的能量加值。<br> 你在后续的擒抱对抗/压制行为中可以用操控+专注+忍术代替力量+武技+肉搏专业进行检定。<br> 对方若进入擒抱状态，则会同时陷入C级环境来源的水中环境中，直到其不再处于擒抱状态。<br> 对方在水中环境想要通过游泳避免困难地形的DC提高至13点，且需要游泳检定承受其在擒抱对抗中的失败值点环境减值。<br> 你在维持非压制状态下的擒抱状态时，只需要一个可用肢体与一个迅捷动作即可维持对目标的擒抱状态。<br> 若你在一次擒抱对抗中胜出的数量比对方的力量值更高或是对方已经被你压制，你可以利用对方的身体进行主动掩蔽。</p><p>【水遁·水阵壁】<br> C+1000<br> 消耗能量：6点<br> 使用动作：移动<br> 遁术性质：水<br> 持续时间：一轮<br> 目标：自身<br> 忍术成分：姿势、语言、忍印<br> 距离：操控*2米<br> 描述：从口中吐出瀑布般的水流抵挡敌人的攻击。</p><p>效果：此术不会在消耗移动动作后立即生效。当你使用此忍术以后仅一次，你在回合外受到敌方攻击时，可以一个反射动作吐出水流阻挡对方的这一次攻击，你抵消专注等级点的对方攻击成功数。<br> 喷吐出的水流同时会在面对攻击方向上升起一道宽高均为10米的水幕壁垒，壁垒后方的所有单位在应对此方向上袭来的远程攻击时获得等同你操控属性点的偏斜防御。这一效果持续至你的回合开始。</p><p>【水遁·水刃斩】<br> C+1000<br> 消耗能量：6点<br> 使用动作：迅捷<br> 遁术性质：水<br> 持续时间：一场景<br> 目标：单个物品<br> 忍术成分：姿势、语言、忍印<br> 距离：触及范围<br> 描述：将水遁附带在苦无上斩杀敌人</p><p>效果：选择一个触及范围内的武器，给武器附魔，武器额外获得【5高速】【5破甲】以及5dp攻击上冻寒能量加值。一个单位只能同时享有一次此加值。</p><p>【水遁·水断波】<br> B+2000<br> 消耗能量：10点<br> 使用动作：标准<br> 遁术性质：水<br> 持续时间：立即<br> 目标：扇形群体<br> 忍术成分：姿势、语言、忍印<br> 距离：操控*5米<br> 描述：从口中吐出超远距离的超高压直线水柱化为锋利的水刀刃，连续切断神树的树根。其威力犹如风遁一样，能够有效地切断目标。</p><p>效果：对面前扇形区域内所有敌方单位进行一次忍术攻击检定，此次伤害造成挥砍伤害，附带【破魔10】【破甲10】【超级贯穿】，对方需要以反射豁免，若失败则承受差额伤害并被击退失败值+50米距离。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',30)])])}const f=p(s,[["render",o]]);export{C as __pageData,f as default};
